#include<iostream>#include<algorithm>#include<vector>#include<set>#include<unordered_map>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<vector<ll>> a(n,vector<ll>(n));        ll max_freq=0;        unordered_map<ll,ll> map;        for(int i=0;i<n;i++){            for(int j=0;j<n;j++){                cin>>a[i][j];                                map[a[i][j]]++;                if(map[a[i][j]]>max_freq){                    max_freq=map[a[i][j]];                }            }        }        ll total_ele= n*n;        if(max_freq<= (total_ele - n)){            cout<<"YES\n";        }        else{            cout<<"NO\n";        }     }}